-- Migration 0012: Built-in prompt template library
-- Curated from popular open-source GPT-4o / gpt-image prompt collections
-- (e.g. jamez-bondos/awesome-gpt4o-images, CC BY 4.0). Used as a built-in,
-- read-only library that users can apply directly in the canvas / generator.

CREATE TABLE "prompt_template" (
    "id" TEXT PRIMARY KEY,
    "title" TEXT NOT NULL,
    "content" TEXT NOT NULL,
    "category" TEXT,
    "tags" TEXT NOT NULL DEFAULT '[]',
    "coverUrl" TEXT,
    "needsReference" INTEGER NOT NULL DEFAULT 0,
    "sortOrder" INTEGER NOT NULL DEFAULT 0,
    "createdAt" TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE INDEX "idx_prompt_template_category" ON "prompt_template"("category");
CREATE INDEX "idx_prompt_template_sort" ON "prompt_template"("sortOrder");

