INSERT INTO "prompt_template" ("id", "title", "content", "category", "tags", "needsReference", "sortOrder") VALUES
('tpl-ghibli', '吉卜力风格', '以吉卜力风格重绘这张照片。如果背景里有不合适（敏感）的内容，可以进行修改或删除。', '风格转换', '["风格","吉卜力","图生图"]', 1, 1),
('tpl-pixar', '皮克斯 3D 风格', '以皮克斯 3D 风格重绘这张照片。', '风格转换', '["风格","皮克斯","3D","图生图"]', 1, 2),
('tpl-3dchibi', '3D Q版风格', '将场景中的角色转化为3D Q版风格，同时保持原本的场景布置和服装造型不变。', '风格转换', '["3D","Q版","图生图"]', 1, 3),
('tpl-cyberpunk', '赛博朋克城市夜景', '赛博朋克风格的未来都市夜景，霓虹灯光在湿润的街道上反射，高耸的摩天楼与全息广告牌，浓厚的雾气与体积光，电影感构图，高细节，4K 画质。', '风格转换', '["赛博朋克","场景","氛围","文生图"]', 0, 4),
('tpl-figure-anime', '定制动漫手办', '生成一张摆放于桌面上的动漫风格手办照片，以日常随手用手机拍摄的轻松休闲视角呈现。手办模型以附件中人物照片为基础，精确还原照片中人物的全身姿势、面部表情以及服装造型，确保手办全身完整呈现。整体设计精致细腻，头发与服饰采用自然柔和的渐变色彩与细腻质感，风格偏向日系动漫风，细节丰富，质感真实，观感精美。', '3D·手办', '["手办","动漫","3D","图生图"]', 1, 5),
('tpl-funkopop', 'Funko Pop 公仔', '把照片中的人物变成 Funko Pop 公仔包装盒的风格，以等距视角（isometric）呈现，并在包装盒上标注标题。包装盒内展示的是照片中人物形象，旁边搭配有人物的必备物品。同时，在包装盒旁边还应呈现该公仔本体的实物效果，采用逼真的、具有真实感的渲染风格。', '3D·手办', '["手办","Funko","公仔","图生图"]', 1, 6),
('tpl-knitdoll', '可爱针织玩偶', '一张特写、构图专业的照片，展示一个手工钩织的毛线玩偶被双手轻柔地托着。玩偶造型圆润，还原上传图片人物的可爱Q版形象，色彩对比鲜明，细节丰富。持玩偶的双手自然、温柔，手指姿态清晰可见，皮肤质感与光影过渡自然，展现出温暖且真实的触感。背景轻微虚化，表现为室内环境，有温暖的木质桌面和从窗户洒入的自然光，营造出舒适、亲密的氛围。整体画面传达出精湛的工艺感与被珍视的温馨情绪。', '3D·手办', '["玩偶","针织","可爱","图生图"]', 1, 7),
('tpl-bobblehead', '自拍生成摇头娃娃', '将这张照片变成一个摇头娃娃：头部稍微放大，保持面部准确，身体卡通化。把它放在书架上（也可替换为办公桌、中性背景或透明背景）。', '3D·手办', '["摇头娃娃","卡通","图生图"]', 1, 8),
('tpl-jewelbox', '3D 情侣珠宝盒摆件', '根据照片上的内容打造一款细致精美、萌趣可爱的3D渲染收藏摆件，装置在柔和粉彩色调、温馨浪漫的展示盒中。展示盒为浅奶油色搭配柔和的金色装饰，形似精致的便携珠宝盒。打开盒盖，呈现出一幕温暖浪漫的场景：两位Q版角色正甜蜜相望。盒顶雕刻着祝福字样，周围点缀着小巧精致的星星与爱心图案。两人都拥有大而闪亮、充满表现力的眼睛，以及柔和、温暖的微笑。盒内以温暖的柔和光线进行照明，背景中漂浮着花瓣点缀气氛。尺寸：9:16。', '3D·手办', '["3D","情侣","摆件","图生图"]', 1, 9),
('tpl-bwportrait', '黑白肖像艺术', '高分辨率的黑白肖像艺术作品，采用编辑类和艺术摄影风格。背景呈现柔和渐变效果，从中灰过渡到近乎纯白，营造出层次感与寂静氛围。细腻的胶片颗粒质感为画面增添了一种可触摸的、模拟摄影般的柔和质地。一个模糊却惊艳的面容从阴影中隐约浮现，并非传统的摆拍，而像是被捕捉于思索或呼吸之间的瞬间。一束温柔的定向光，柔和地漫射开来，轻抚面颊曲线。其余部分以大量负空间占据，刻意保持简洁，使画面自由呼吸。整体氛围抽象却深具人性：亲密、永恒、令人怅然的美。', '人像·摄影', '["肖像","黑白","摄影","文生图"]', 0, 10),
('tpl-frostedglass', '磨砂玻璃后的剪影', '一张黑白照片，展示了一个主体在磨砂或半透明表面后的模糊剪影。其局部轮廓清晰，紧贴表面，与其余朦胧、模糊的身影形成鲜明对比。背景是柔和的灰色渐变色调，增强了神秘和艺术的氛围。', '人像·摄影', '["剪影","黑白","艺术","文生图"]', 0, 11),
('tpl-animalselfie', '动物与地标自拍', '三只动物在标志性地标前的特写自拍照，它们表情各异，拍摄于黄金时刻，采用电影般的灯光。动物们靠近镜头，头挨着头，模仿自拍姿势，展现出喜悦、惊讶和平静的表情。背景展示了地标完整的建筑细节，光线柔和，氛围温暖。采用摄影感、写实卡通风格拍摄，高细节，1:1 宽高比。', '人像·摄影', '["自拍","动物","写实","文生图"]', 0, 12),
('tpl-titanic', '泰坦尼克号经典姿势', '将附图中的人物转换成可爱Q版3D造型。场景：在豪华游轮最顶尖的尖船头，男士带着女士站在船头，男士双手搂着女士的腰，女士双臂伸展穿着连衣裙，迎着风，脸上洋溢着自由与畅快。此时天色呈现出黄昏的暖色调，大海在船下延展。除了人物用Q版3D造型以外，其他环境都是实物。', '创意·设计', '["Q版","3D","情侣","图生图"]', 1, 13),
('tpl-chinesewedding', '中式婚礼 Q版', '将照片里的两个人转换成Q版 3D人物，中式古装婚礼，大红颜色，背景为囍字剪纸风格图案。服饰写实：男士身着长袍马褂，主体红色，金色绣龙纹图案，胸前系着大红花；女士身穿秀禾服，红色为基调，饰有金色花纹与凤凰刺绣，头上搭配花朵发饰。头饰：男士中式状元帽，红色金纹，帽顶金饰；女士凤冠造型，红色花朵为中心，金色立体装饰与垂坠流苏，华丽富贵，古典韵味十足。', '创意·设计', '["Q版","3D","婚礼","图生图"]', 1, 14),
('tpl-doodlead', '实物与手绘涂鸦广告', '一则简约且富有创意的广告，设置在纯白背景上。一个真实的物体与手绘黑色墨水涂鸦相结合，线条松散而俏皮。涂鸦以巧妙、富有想象力的方式与物体互动。在顶部或中部加入粗体黑色广告文案文字，在底部清晰放置品牌标志。视觉效果应简洁、有趣、高对比度且构思巧妙。', '创意·设计', '["广告","创意","涂鸦","文生图"]', 0, 15),
('tpl-crtascii', '复古 CRT 启动屏', '复古CRT电脑启动屏幕，扫描线与微微发光的荧光绿文字，最终显示为某个形状或标志的 ASCII 艺术。', '创意·设计', '["复古","ASCII","创意","文生图"]', 0, 16),
('tpl-product-ecom', '电商产品主图', '专业电商产品摄影：产品置于纯净背景上，柔和的工作室灯光，细腻的反光与阴影，突出材质细节，居中构图，高分辨率，干净通透，适合作为电商主图。', '创意·设计', '["电商","产品","摄影","文生图"]', 0, 17),
('tpl-logo', '极简品牌 Logo', '为品牌设计一个极简、现代的矢量 Logo，简洁的几何造型，扁平设计，单色或双色配色，纯白背景，居中，clean，适合作为应用图标与品牌标识。', '创意·设计', '["Logo","品牌","矢量","文生图"]', 0, 18);
